import { mkdir } from "node:fs/promises";
import path from "node:path";
import QRCode from "qrcode";
import { normalizeText, toQrOptions } from "./shared.js";
const PNG_DATA_URL_PREFIX = "data:image/png;base64,";
export async function renderPngDataUrl(text, options = {}) {
    return await QRCode.toDataURL(normalizeText(text), {
        ...toQrOptions(options),
        type: "image/png",
    });
}
export async function renderPngBase64(text, options = {}) {
    const dataUrl = await renderPngDataUrl(text, options);
    if (!dataUrl.startsWith(PNG_DATA_URL_PREFIX)) {
        throw new Error("Expected qrcode to return a PNG data URL.");
    }
    return dataUrl.slice(PNG_DATA_URL_PREFIX.length);
}
export async function writePngFile(text, filePath, options = {}) {
    if (typeof filePath !== "string" || filePath.trim().length === 0) {
        throw new Error("PNG output path must not be empty.");
    }
    await mkdir(path.dirname(filePath), { recursive: true });
    await QRCode.toFile(filePath, normalizeText(text), {
        ...toQrOptions(options),
        type: "png",
    });
    return filePath;
}
